// SOURCE_COLORS is loaded from /colors.js (generated by crawler.py)

const AD_EVERY = 25; // insert an ad slot after every N visible articles
// Icons reference the shared <symbol> sprite in the page (defined in template.html)
// via <use>, so rows stay tiny. Must match the crawler's OPEN_SVG/LINK_SVG/HIDE_BTN.
const OPEN_SVG = '<svg width="18" height="18"><use href="#ico-arrow"/></svg>';
const LINK_SVG = '<svg width="18" height="18"><use href="#ico-link"/></svg>';
// Eye toggle next to the time: hides this source from the feed (#4).
const HIDE_BTN = '<button class="hide-src" type="button" aria-label="Hide source" title="Hide source"><svg width="14" height="14"><use href="#ico-eye-off"/></svg></button>';

// Origin (scheme://host) of an article URL — the source portal's home (#4).
function portalHome(u) {
  try { return new URL(u).origin; } catch (e) { return u; }
}

// Stable per-article anchor id (mirrors article_id() in crawler.py). Used for
// "Share" deep-links: https://all.news/#<id>
function slugify(s) {
  return (s || "")
    .toLowerCase()
    .replace(/ä/g, "ae").replace(/ö/g, "oe").replace(/ü/g, "ue").replace(/ß/g, "ss")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60)
    .replace(/^-+|-+$/g, "");
}
function djb2(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h * 33) + s.charCodeAt(i)) >>> 0;
  return h;
}
function articleId(a) {
  return `${slugify(a.title)}-${djb2(a.url).toString(16)}`;
}

function fmtTime(s) {
  if (!s) return "";
  const d = new Date(s);
  if (isNaN(d)) return "";
  // Swiss local HH:MM (mirrors fmt_time in crawler.py)
  return d.toLocaleString("de-CH", {
    timeZone: "Europe/Zurich",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function ts(a) {
  const d = new Date(a.published);
  return isNaN(d) ? 0 : d.getTime();
}

// Preferred source order; listed sources rank first (in this order), rest after.
// Prioritize sources with fewer updates for fairer visibility.
const SOURCE_PRIORITY = [
  "Inside Paradeplatz",
  "Infosperber",
  "Rathuus",
  "Inside IT",
  "Nebelspalter",
  "Bilanz",
  "Republik",
  "Weltwoche",
  "NZZ",
];
function prio(a) {
  const i = SOURCE_PRIORITY.indexOf(a.source);
  return i === -1 ? SOURCE_PRIORITY.length : i;
}

function sortArticles(articles, mode) {
  const out = articles.slice();
  if (mode === "source") {
    out.sort((a, b) => a.source.localeCompare(b.source) || ts(b) - ts(a));
  } else {
    out.sort((a, b) => ts(b) - ts(a) || prio(a) - prio(b));
  }
  return out;
}

// Sorting depends only on (current, mode) — never on which filters are active —
// so toggling a source/country/language must not re-sort the whole list, only
// re-filter it. Cache the sorted array per mode; invalidate when `current` is
// replaced (a new dataset load). Callers only .filter() the result (which builds
// a fresh array), so handing back the cached array is safe.
let _sortCache = new Map();   // mode -> sorted array
let _sortCacheFor = null;     // the `current` reference the cache was built from
function sortedArticles(articles, mode) {
  if (articles !== _sortCacheFor) { _sortCache.clear(); _sortCacheFor = articles; }
  let out = _sortCache.get(mode);
  if (!out) { out = sortArticles(articles, mode); _sortCache.set(mode, out); }
  return out;
}

// ---------- Persistent filter state (localStorage, never the URL) ----------
// The durable filters — excluded sources, countries, languages — live in
// localStorage, keyed per-origin. Nothing is stored in the URL: a selection can be
// large (dozens of sources / countries / languages) and would blow past URL length
// limits, the clean URL stays shareable without leaking a visitor's personal
// filter, and because localStorage is shared across the origin the same filter
// applies on the home feed, every archive day page and every tab automatically.
// Search is deliberately session-only (sessionStorage): it survives a reload but is
// forgotten when the session ends, so a returning visitor never lands on a stale
// query. (Article deep-links still use the #hash; archive days and landing pages
// still use the path.)
const STORE_COUNTRY = "allnews.country";   // "all" | "" (none) | csv of country codes
const STORE_LANG = "allnews.lang";         // "all" | "" (none) | csv of language codes
const STORE_EXCLUDE = "allnews.exclude";   // csv of excluded source names ("" = none)
const STORE_QUERY = "allnews.query";       // free-text search string (sessionStorage)
const STORE_WELCOMED = "allnews.welcomed"; // "1" once the welcome modal was dismissed
function lsGet(k) { try { return localStorage.getItem(k); } catch (e) { return null; } }
function lsSet(k, v) { try { localStorage.setItem(k, v); } catch (e) { /* ignore */ } }
function ssGet(k) { try { return sessionStorage.getItem(k); } catch (e) { return null; } }
function ssSet(k, v) { try { sessionStorage.setItem(k, v); } catch (e) { /* ignore */ } }
const _csvToSet = (s) =>
  new Set((s || "").split(",").map((x) => x.trim().toLowerCase()).filter(Boolean));

// Excluded sources (lowercased). Empty set = every source shown.
const excluded = _csvToSet(lsGet(STORE_EXCLUDE));
// Country / language filters use an INCLUDE model with an explicit "all" flag:
//   <flag> true                      → show all (group header "select all")
//   <flag> false + non-empty set     → show only those
//   <flag> false + empty set         → show none (group header "deselect all")
// Stored value: "all" (or absent) = all, "" = none, csv = only those.
// The welcome modal seeds the country set with the visitor's primary country.
const _savedCountry = lsGet(STORE_COUNTRY);
const _savedLang = lsGet(STORE_LANG);
const includedCountries = _csvToSet(_savedCountry === "all" ? "" : _savedCountry);
let countriesAll = _savedCountry === null || _savedCountry === "all";
const includedLangs = _csvToSet(_savedLang === "all" ? "" : _savedLang);
let langsAll = _savedLang === null || _savedLang === "all";

function countryAllowed(c) { return countriesAll || includedCountries.has((c || "").toLowerCase()); }
function langAllowed(l) { return langsAll || includedLangs.has((l || "").toLowerCase()); }
// ISO 3166-1 alpha-2 -> display name. Extend as the source scope widens.
const COUNTRY_NAMES = {
  CH: "Switzerland", DE: "Germany", FR: "France",
  GB: "United Kingdom", US: "United States", IT: "Italy", ES: "Spain",
  NL: "Netherlands", BE: "Belgium", AT: "Austria", PT: "Portugal", IE: "Ireland",
  PL: "Poland", SE: "Sweden", NO: "Norway", DK: "Denmark", FI: "Finland",
  GR: "Greece", CZ: "Czechia", HU: "Hungary", RO: "Romania", UA: "Ukraine", TR: "Turkey",
  CA: "Canada", MX: "Mexico", BR: "Brazil", AR: "Argentina", CO: "Colombia", PE: "Peru",
  CL: "Chile",
  AU: "Australia", NZ: "New Zealand",
  IN: "India", JP: "Japan", KR: "South Korea", SG: "Singapore", ID: "Indonesia",
  PH: "Philippines", VN: "Vietnam", PK: "Pakistan", IL: "Israel", QA: "Qatar", HK: "Hong Kong",
  CN: "China", RU: "Russia",
};
// ISO 639-1 -> display name (shown in the source's own language).
const LANG_NAMES = {
  de: "Deutsch", fr: "Français", en: "English", it: "Italiano", es: "Español",
  nl: "Nederlands", pt: "Português", pl: "Polski", sv: "Svenska", no: "Norsk",
  da: "Dansk", fi: "Suomi", el: "Ελληνικά", cs: "Čeština", hu: "Magyar", ro: "Română",
  uk: "Українська", tr: "Türkçe", ja: "日本語", id: "Bahasa Indonesia", vi: "Tiếng Việt",
  he: "עברית", ar: "العربية", zh: "中文", ru: "Русский", ko: "한국어",
};
// ISO 639-1 -> English name (mirrors LANG_EN_NAMES in crawler.py). Used only to
// resolve landing-page URL slugs (/news/<country>/<lang>/) back to codes.
const LANG_EN_NAMES = {
  de: "German", fr: "French", en: "English", it: "Italian", es: "Spanish",
  nl: "Dutch", pt: "Portuguese", pl: "Polish", sv: "Swedish", no: "Norwegian",
  da: "Danish", fi: "Finnish", el: "Greek", cs: "Czech", hu: "Hungarian", ro: "Romanian",
  uk: "Ukrainian", tr: "Turkish", ja: "Japanese", id: "Indonesian", vi: "Vietnamese",
  he: "Hebrew", ar: "Arabic", zh: "Chinese", ru: "Russian", ko: "Korean",
};
// Lowercase ASCII slug (mirrors slugify() in crawler.py), + reverse maps so a
// landing URL like /news/united-kingdom/english/ resolves to { GB, en }.
function slugify(s) {
  return (s || "").normalize("NFKD").replace(/[̀-ͯ]/g, "")
    .toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}
const COUNTRY_BY_SLUG = {};
for (const cc in COUNTRY_NAMES) COUNTRY_BY_SLUG[slugify(COUNTRY_NAMES[cc])] = cc;
const LANG_BY_SLUG = {};
for (const l in LANG_EN_NAMES) LANG_BY_SLUG[slugify(LANG_EN_NAMES[l])] = l;

const EN_MONTHS = ["", "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"];
function fmtDayEn(iso) {
  const [y, m, d] = (iso || "").split("-");
  return EN_MONTHS[+m] ? `${+d} ${EN_MONTHS[+m]} ${y}` : iso;
}
// Today's date (YYYY-MM-DD) in Swiss local time — matches the crawler's "today".
function todayISO() {
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: "Europe/Zurich", year: "numeric", month: "2-digit", day: "2-digit",
  }).format(new Date());
}
// Badge color: brand color if listed, else a stable hashed hue (mirrors
// color_for() in crawler.py) so every source gets a distinct color.
function colorFor(s) {
  return SOURCE_COLORS[s] || `hsl(${djb2(s) % 360}, 65%, 45%)`;
}

// Pill text colour: black on a light background, white on a dark one (mirrors
// text_color() in crawler.py).
function textColor(bg) {
  const m = /^#([0-9a-f]{6})$/i.exec(bg || "");
  if (!m) return "#fff";
  const n = parseInt(m[1], 16);
  const r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 > 0.6 ? "#000" : "#fff";
}

function isExcluded(a) {
  return excluded.has(a.source.toLowerCase()) ||
         !countryAllowed(a.country) ||
         !langAllowed(a.lang);
}

// Free-text search over title + source, kept for the session only (sessionStorage).
let query = (ssGet(STORE_QUERY) || "").trim().toLowerCase();

function matchesQuery(a) {
  if (!query) return true;
  return a.title.toLowerCase().includes(query) ||
         a.source.toLowerCase().includes(query);
}

// Persist the whole filter selection to localStorage. Landing pages are pinned by
// their /news/<country>/<lang>/ path, so filtering within one is transient and must
// not overwrite the visitor's remembered home preferences.
function persistFilters() {
  if (isLanding) return;
  lsSet(STORE_EXCLUDE, [...excluded].join(","));
  lsSet(STORE_COUNTRY, countriesAll ? "all" : [...includedCountries].join(","));
  lsSet(STORE_LANG, langsAll ? "all" : [...includedLangs].join(","));
  ssSet(STORE_QUERY, query); // session-only
  lsSet(STORE_WELCOMED, "1");
}

// HTML-escape for text and attribute values (mirrors escape() in crawler.py).
function esc(s) {
  return (s == null ? "" : String(s))
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

// One row as an HTML string (mirrors render_article_html in crawler.py). Building
// the whole list as a single string + one innerHTML assignment is far faster than
// per-node DOM construction; clicks are handled by delegation, so no per-row
// listeners are needed.
function articleHTML(a) {
  const color = colorFor(a.source);
  const fg = textColor(color);
  const url = esc(a.url);
  const home = esc(portalHome(a.url));
  return `<li class="article" id="${esc(articleId(a))}" data-lang="${esc(a.lang || "de")}" data-country="${esc(a.country || "CH")}">` +
    `<div class="meta-col">` +
    `<a class="source" href="${home}" target="_blank" rel="noopener nofollow ugc" style="background:${color};color:${fg}">${esc(a.source)}</a>` +
    `<span class="time">${esc(fmtTime(a.published))} ${HIDE_BTN}</span>` +
    `</div>` +
    `<a class="title" href="${url}" target="_blank" rel="noopener nofollow ugc">${esc(a.title)}</a>` +
    `<div class="row-actions">` +
    // Visible labels stay identical on every row; the accessible name carries the
    // headline so a screen reader announces which article the action belongs to (#49).
    `<a class="row-act open" href="${url}" target="_blank" rel="noopener nofollow ugc" aria-label="Open article: ${esc(a.title)}"><span class="label">Open article</span> ${OPEN_SVG}</a>` +
    `<button class="row-act share" type="button" aria-label="Share article: ${esc(a.title)}"><span class="label">Share article</span> ${LINK_SVG}</button>` +
    `</div></li>`;
}

const AD_SLOT_HTML = '<li class="ad-slot">Werbung</li>';
const PAGE = 120; // articles rendered per lazy batch (matches SSR_LIMIT head)

// Reflect the number of currently-visible articles in the wordmark badge.
function setCountBadge(n) {
  const el = document.querySelector(".count-badge");
  if (el) el.textContent = n;
}

// Lazy/windowed rendering: render() lays down the first PAGE rows + a scroll
// sentinel; appendBatch() adds the next PAGE as the sentinel nears the viewport.
// The full list can be thousands of rows, so we never build them all at once.
let visibleArticles = [];
let shownCount = 0;
let scrollObserver = null;

function render(articles, mode) {
  const list = document.getElementById("list");
  if (!list) return;
  visibleArticles = sortedArticles(articles, mode)
    .filter((a) => !isExcluded(a) && matchesQuery(a));
  setCountBadge(visibleArticles.length);
  if (scrollObserver) { scrollObserver.disconnect(); scrollObserver = null; }
  list.innerHTML = "";
  shownCount = 0;
  if (!visibleArticles.length && query) {
    // No matches for the search term — say so instead of a blank list (#25).
    list.innerHTML = `<li class="no-results">No results for “${esc(query)}”</li>`;
    return;
  }
  appendBatch();
  ensureHashVisible(); // render far enough to reveal a deep-linked article
  highlightFromHash();
}

function appendBatch() {
  const list = document.getElementById("list");
  if (!list) return;
  const end = Math.min(shownCount + PAGE, visibleArticles.length);
  const parts = [];
  for (let i = shownCount; i < end; i++) {
    parts.push(articleHTML(visibleArticles[i]));
    if ((i + 1) % AD_EVERY === 0 && i + 1 < visibleArticles.length) parts.push(AD_SLOT_HTML);
  }
  const sentinel = document.getElementById("scrollSentinel");
  if (sentinel) sentinel.insertAdjacentHTML("beforebegin", parts.join(""));
  else list.insertAdjacentHTML("beforeend", parts.join(""));
  shownCount = end;
  updateSentinel();
}

function updateSentinel() {
  const list = document.getElementById("list");
  let sentinel = document.getElementById("scrollSentinel");
  if (shownCount >= visibleArticles.length) { // all rendered — tear down
    if (sentinel) sentinel.remove();
    if (scrollObserver) { scrollObserver.disconnect(); scrollObserver = null; }
    return;
  }
  if (!sentinel) {
    sentinel = document.createElement("li");
    sentinel.id = "scrollSentinel";
    sentinel.className = "scroll-sentinel";
    list.appendChild(sentinel);
    scrollObserver = new IntersectionObserver((entries) => {
      if (entries.some((e) => e.isIntersecting)) appendBatch();
    }, { rootMargin: "1000px" });
    scrollObserver.observe(sentinel);
  } else {
    list.appendChild(sentinel); // keep it last after the freshly inserted rows
  }
}

// If the URL targets an article (#id) beyond the current window, render up to it.
function ensureHashVisible() {
  const id = decodeURIComponent(location.hash.slice(1));
  if (!id || shownCount >= visibleArticles.length) return;
  const idx = visibleArticles.findIndex((a) => articleId(a) === id);
  while (idx >= shownCount && shownCount < visibleArticles.length) appendBatch();
}

function sortMode() {
  const el = document.querySelector('input[name="sort"]:checked');
  return el ? el.value : "date";
}

let current = [];

// True if an article passes the current country + language filters (ignores the
// per-source filter). Used to scope the "Medias" list to the active selection.
function passesCountryLang(a) {
  return countryAllowed(a.country) && langAllowed(a.lang);
}

// A filter group offering a single option has nothing to choose between: leaving it
// deselectable only lets the visitor empty their own feed (common for the language
// group in single-language countries). Such an option is forced on and locked (#51).
// Returns true if the caller should skip wiring a click handler.
function lockSoleOption(btn, count) {
  if (count !== 1) return false;
  btn.setAttribute("aria-pressed", "true");
  // aria-disabled, not the `disabled` property: a disabled button drops out of the
  // accessibility tree, so a screen reader would never announce the one language
  // that is actually active. This keeps it focusable and announced, just inert —
  // no click handler is wired, so activating it does nothing.
  btn.setAttribute("aria-disabled", "true");
  btn.classList.add("locked");
  btn.title = "Only option available";
  return true;
}

// "Medias" filter: clickable source toggles, persisted in localStorage. Only lists
// sources whose articles pass the active country/language filter, so toggling a
// country or language shows/hides its sources here too.
function buildFilters(articles) {
  const box = document.getElementById("filters");
  if (!box) return;
  box.innerHTML = "";
  const sources = [...new Set(articles.filter(passesCountryLang).map((a) => a.source))].sort();
  for (const s of sources) {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "opt";
    btn.textContent = s;
    const on = () => !excluded.has(s.toLowerCase());
    btn.setAttribute("aria-pressed", String(on()));
    if (lockSoleOption(btn, sources.length)) {
      excluded.delete(s.toLowerCase());   // the only source must stay visible
      persistFilters();
      box.appendChild(btn);
      continue;
    }
    btn.addEventListener("click", () => {
      if (on()) excluded.add(s.toLowerCase());
      else excluded.delete(s.toLowerCase());
      btn.setAttribute("aria-pressed", String(on()));
      persistFilters();
      render(current, sortMode());
    });
    box.appendChild(btn);
  }
}

// Every country code we can show (uppercase), from the manifest when present
// (complete without loading every shard), else derived from the loaded articles
// (archive pages, or before the manifest arrives).
function availableCountryCodes() {
  const codes = manifest && manifest.countries
    ? manifest.countries.map((c) => (c.code || "").toUpperCase())
    : [...new Set(current.map((a) => (a.country || "").toUpperCase()))];
  return codes.filter(Boolean)
    .sort((a, b) => (COUNTRY_NAMES[a] || a).localeCompare(COUNTRY_NAMES[b] || b));
}

// "Countries" filter (INCLUDE model + countriesAll flag): pressed = country shown.
// The group header does select-all / deselect-all (see wireHeaderToggle). Driven by
// the manifest so every country is selectable before its shard is downloaded.
function buildCountryFilters() {
  const box = document.getElementById("countryFilters");
  if (!box) return;
  box.innerHTML = "";
  const codes = availableCountryCodes();
  const allLc = codes.map((c) => c.toLowerCase());
  for (const code of codes) {
    const lc = code.toLowerCase();
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "opt";
    btn.textContent = COUNTRY_NAMES[code] || code;
    btn.setAttribute("aria-pressed", String(countryAllowed(lc)));
    if (lockSoleOption(btn, codes.length)) {
      countriesAll = true;                // the only country must stay selected
      includedCountries.clear();
      persistFilters();
      box.appendChild(btn);
      continue;
    }
    btn.addEventListener("click", () => {
      const wasNone = noCountriesSelected();
      if (countriesAll) {                 // materialize "all", then turn this one off
        allLc.forEach((c) => includedCountries.add(c));
        countriesAll = false;
        includedCountries.delete(lc);
      } else if (includedCountries.has(lc)) {
        includedCountries.delete(lc);
      } else {
        includedCountries.add(lc);
      }
      // First country picked after "deselect all": it's now the sole selection, and
      // its languages + media are restored so the feed actually shows (they were
      // cleared by the deselect-all cascade).
      if (wasNone) selectAllLangsAndMedia();
      if (includedCountries.size === allLc.length) { // everything selected → "all"
        countriesAll = true;
        includedCountries.clear();
      }
      pruneLangsToCountries();      // drop languages the selection no longer publishes
      afterFilterChange();
    });
    box.appendChild(btn);
  }
}

// Languages published by the given countries (lowercased codes). Uses the manifest
// when present, so it's correct even for a just-selected country whose shard hasn't
// downloaded yet; otherwise falls back to the loaded articles.
function langsForCountries(codes) {
  const avail = new Set();
  if (manifest && manifest.countries) {
    const want = new Set(codes);
    for (const c of manifest.countries) {
      if (want.has((c.code || "").toLowerCase()))
        (c.langs || []).forEach((l) => avail.add((l || "").toLowerCase()));
    }
  } else {
    for (const a of current) {
      if (codes.includes((a.country || "").toLowerCase())) avail.add((a.lang || "").toLowerCase());
    }
  }
  return avail;
}

// Drop selected languages not published by the currently-selected countries, so
// switching countries never leaves a stale language pick that empties the feed.
function pruneLangsToCountries() {
  if (langsAll || countriesAll) return;
  const avail = langsForCountries([...includedCountries]);
  for (const l of [...includedLangs]) if (!avail.has(l)) includedLangs.delete(l);
}

// Persist + rebuild all panels + re-render after any country/language change.
// Selecting a new country may require its shard, so fetch it before rendering.
function afterFilterChange() {
  // Any explicit filter click means "honor exactly what I chose" — even if it
  // empties the feed. Clear the auto-default flag so relaxIfEmpty() stops widening
  // the selection behind the user's back (which otherwise reverts a "deselect all").
  autoDefault = false;
  persistFilters();
  buildCountryFilters();          // instant: from the manifest, no data needed
  updateAllToggles();
  ensureCountryData().then(() => {
    if (autoDefault) { relaxIfEmpty(); return ensureCountryData(); }
    return current;
  }).then(() => {
    buildLangFilters(current);
    buildFilters(current);
    render(current, sortMode());
  });
}

// "Select all" / "Deselect all" button label reflects each group's state (#2).
function updateAllToggles() {
  const set = (group, allOn) => {
    const btn = document.querySelector(`.fs-all[data-group="${group}"]`);
    if (btn) btn.textContent = allOn ? "Deselect all" : "Select all";
  };
  set("country", countriesAll);
  set("lang", langsAll);
  set("media", excluded.size === 0); // no source excluded = all shown
}

// Archive section: today's date (the home feed, active) + up to 30 past archive
// days, all listed uniformly. Built once from /archive/index.json. Links are plain
// paths — the active filter lives in localStorage, which every archive day page
// reads on load, so it carries across without being threaded through the URL.
let archiveDatesPromise = null;
function loadArchiveDates() {
  if (archiveDatesPromise) return archiveDatesPromise;
  archiveDatesPromise = fetch("/archive/index.json")
    .then((r) => r.json())
    .then((idx) => { buildArchiveDays(idx.dates || []); return idx.dates; })
    .catch(() => { archiveDatesPromise = null; });
  return archiveDatesPromise;
}
function buildArchiveDays(dates) {
  const box = document.getElementById("archiveDays");
  if (!box) return;
  box.innerHTML = "";
  const today = todayISO();
  const a0 = document.createElement("a");
  a0.className = "today";
  a0.href = "/";
  a0.textContent = fmtDayEn(today); // today's date (the home feed), not the word "Today"
  box.appendChild(a0);
  const past = dates.slice().sort().reverse().filter((d) => d < today).slice(0, 30);
  for (const d of past) {
    const a = document.createElement("a");
    a.className = "past";
    a.href = `/archive/${d}.html`;
    a.target = "_blank";          // open the archive day in a new tab
    a.rel = "noopener";
    a.textContent = fmtDayEn(d);
    box.appendChild(a);
  }
}

// True while every country is deselected (the explicit "none" state).
function noCountriesSelected() { return !countriesAll && includedCountries.size === 0; }
// Exclude every currently-loaded source (the "deselect all media" state).
function excludeAllSources() {
  for (const a of current) excluded.add((a.source || "").toLowerCase());
}
// Reset languages + media back to "all shown" — used when a country is (re)selected
// from the fully-deselected state, so its feed appears in full instead of staying
// empty behind the cascade-deselected languages/media.
function selectAllLangsAndMedia() {
  langsAll = true; includedLangs.clear();
  excluded.clear();
}

// Group-header select-all / deselect-all toggles (desktop).
function toggleAllCountries() {
  const wasNone = noCountriesSelected();
  countriesAll = !countriesAll;           // all ⇄ none
  includedCountries.clear();
  if (!countriesAll) {
    // Deselecting every country empties the feed, so cascade: Languages and Media
    // also read as fully deselected instead of leaving a stale selection. They're
    // restored the moment a country is picked again (see below / the country click).
    langsAll = false; includedLangs.clear();
    excludeAllSources();
  } else if (wasNone) {
    selectAllLangsAndMedia();             // "select all" straight out of the none state
  } else {
    pruneLangsToCountries();
  }
  afterFilterChange();
}
function toggleAllLangs() {
  langsAll = !langsAll;                    // all ⇄ none
  includedLangs.clear();
  afterFilterChange();
}
function toggleAllMedia() {
  if (excluded.size === 0) excludeAllSources(); // all shown → exclude every source
  else excluded.clear();                        // some/none shown → clear (show all)
  afterFilterChange();
}

// "Languages" filter (INCLUDE model + langsAll flag, mirrors Countries): pressed =
// shown. Only lists languages the selected countries publish. The group header
// does select-all / deselect-all (see wireHeaderToggle).
function buildLangFilters(articles) {
  const box = document.getElementById("langFilters");
  if (!box) return;
  box.innerHTML = "";
  const pool = articles.filter((a) => countryAllowed(a.country));
  const codes = [...new Set(pool.map((a) => (a.lang || "").toLowerCase()).filter(Boolean))]
    .sort((a, b) => (LANG_NAMES[a] || a).localeCompare(LANG_NAMES[b] || b));
  for (const code of codes) {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "opt";
    btn.textContent = LANG_NAMES[code] || code;
    btn.setAttribute("aria-pressed", String(langAllowed(code)));
    if (lockSoleOption(btn, codes.length)) {
      langsAll = true;                    // the only language must stay selected
      includedLangs.clear();
      persistFilters();
      box.appendChild(btn);
      continue;
    }
    btn.addEventListener("click", () => {
      if (langsAll) {                 // materialize "all available", then turn this off
        codes.forEach((c) => includedLangs.add(c));
        langsAll = false;
        includedLangs.delete(code);
      } else if (includedLangs.has(code)) {
        includedLangs.delete(code);
      } else {
        includedLangs.add(code);
      }
      if (includedLangs.size === codes.length) { langsAll = true; includedLangs.clear(); }
      afterFilterChange();
    });
    box.appendChild(btn);
  }
}

// Instant filter pass over the server-rendered rows, using the data already in
// the markup (data-lang / data-country / source + title text). Runs at boot so a
// URL with filters hides non-matching rows immediately, without waiting for the
// crawled.json fetch + full re-render.
function applySsrFilter() {
  const list = document.getElementById("list");
  if (!list) return;
  let visible = 0;
  for (const li of list.querySelectorAll(".article")) {
    const country = (li.dataset.country || "").toLowerCase();
    const lang = (li.dataset.lang || "").toLowerCase();
    const srcEl = li.querySelector(".source");
    const source = (srcEl ? srcEl.textContent : "").toLowerCase();
    const titleEl = li.querySelector(".title");
    const title = (titleEl ? titleEl.textContent : "").toLowerCase();
    const hide =
      excluded.has(source) ||
      !countryAllowed(country) ||
      !langAllowed(lang) ||
      (query && !(title.includes(query) || source.includes(query)));
    li.style.display = hide ? "none" : "";
    if (!hide) visible++;
  }
  setCountBadge(visible);
}

// ---------- Data layer ----------
// Home: the feed is split into per-country shards (/data/<cc>.json) so a filtered
// visitor downloads only the countries they selected, not the whole world. A small
// manifest (/data/manifest.json) lists every available country + its languages, so
// the picker is complete before any shard loads. The "all countries" view still
// needs everything, so it falls back to the single global /crawled.json.
// Archive day pages keep their single-file model (that day's JSON), loaded lazily.
let DATA_URL = "/crawled.json";  // archive pages point this at the day's JSON
let isArchive = false;
// Landing pages (/news/<country>/<lang>/) pre-set the country+lang filter from the
// path and behave like a filtered home view. The path is the canonical state, so
// persistFilters() is a no-op there and won't overwrite the visitor's home prefs.
let isLanding = false;

// `current` accumulates the articles loaded so far (union of fetched shards, or the
// global set once "all" is loaded). Deselecting a country leaves its articles in
// `current` — they're simply filtered out by countryAllowed — so re-selecting is free.
let manifest = null;                 // { date, countries: [{code, count, langs}] }
let manifestPromise = null;
const shardLoaded = new Set();       // lowercased country codes whose shard is merged
const _mergedUrls = new Set();       // urls already in `current` (cross-shard dedup)
let globalLoaded = false;            // /crawled.json (the all-countries superset) merged
let archivePromise = null;

// De-dupe concurrent fetches of the same URL (e.g. rapid country toggles racing on
// one shard). Cleared on settle; the shardLoaded/globalLoaded guards prevent any
// re-fetch after that, so this only collapses in-flight overlap.
const _inflight = new Map();
function fetchJson(u) {
  if (_inflight.has(u)) return _inflight.get(u);
  const p = fetch(u).then((r) => r.json()).finally(() => _inflight.delete(u));
  _inflight.set(u, p);
  return p;
}

// Merge new articles into `current`, de-duped by URL. Reassigns `current` to a new
// array (not push) so the sorted-array cache, keyed on the array reference, invalidates.
function mergeArticles(arr) {
  const add = [];
  for (const a of arr || []) {
    if (!a || _mergedUrls.has(a.url)) continue;
    _mergedUrls.add(a.url);
    add.push(a);
  }
  if (add.length) current = current.concat(add);
}

function ensureManifest() {
  if (isArchive) return Promise.resolve(null);
  if (manifestPromise) return manifestPromise;
  manifestPromise = fetchJson("/data/manifest.json")
    .then((m) => { manifest = m; return m; })
    .catch(() => { manifestPromise = null; return null; }); // allow retry
  return manifestPromise;
}

// Ensure `current` holds the articles the active country filter needs, fetching and
// merging any missing shards (or the global file for the "all" view). Cheap to call
// repeatedly: shards and the global file are only ever fetched once each.
function ensureCountryData() {
  if (isArchive) {
    if (archivePromise) return archivePromise;
    archivePromise = fetchJson(DATA_URL)
      .then((d) => { mergeArticles(d.articles); return current; })
      .catch(() => { archivePromise = null; return current; });
    return archivePromise;
  }
  if (globalLoaded) return Promise.resolve(current); // superset already loaded
  if (countriesAll) {
    return fetchJson("/crawled.json")
      .then((d) => { mergeArticles(d.articles); globalLoaded = true; return current; })
      .catch(() => current);
  }
  const need = [...includedCountries].filter((c) => !shardLoaded.has(c));
  if (!need.length) return Promise.resolve(current);
  return Promise.all(need.map((c) =>
    fetchJson(`/data/${c}.json`)
      .then((d) => { shardLoaded.add(c); mergeArticles(d.articles); })
      .catch(() => { shardLoaded.add(c); }) // missing shard = no articles for it
  )).then(() => current);
}

// Ensure data for the current selection + (re)build the filter panels. Kept under
// the old name for its many callers; resolves to `current`.
function loadData() {
  return ensureManifest()
    .then(ensureCountryData)
    .then(() => {
      if (autoDefault) { relaxIfEmpty(); return ensureCountryData(); } // relax may widen the set
      return current;
    })
    .then(() => {
      buildFilters(current);
      buildCountryFilters();
      buildLangFilters(current);
      updateAllToggles();
      return current;
    });
}

// Languages we carry for a country, most-frequent first (derived from loaded data).
function langsForCountry(code) {
  if (!code || !current.length) return [];
  const counts = {};
  for (const a of current) {
    if ((a.country || "").toLowerCase() === code.toLowerCase()) {
      const l = (a.lang || "").toLowerCase();
      if (l) counts[l] = (counts[l] || 0) + 1;
    }
  }
  return Object.keys(counts).sort((x, y) => counts[y] - counts[x]);
}

// ---------- View switching (feed / settings / more) ----------
const feedView = document.getElementById("feedView");
const settingsView = document.getElementById("settingsView");
const moreView = document.getElementById("moreView");
const filterToggle = document.getElementById("filterToggle");
const moreToggle = document.getElementById("moreToggle");

function showView(name) {
  if (feedView) feedView.hidden = name !== "feed";
  if (settingsView) settingsView.hidden = name !== "settings";
  if (moreView) moreView.hidden = name !== "more";
  if (filterToggle) filterToggle.setAttribute("aria-expanded", String(name === "settings"));
  if (moreToggle) moreToggle.setAttribute("aria-expanded", String(name === "more"));
  window.scrollTo(0, 0);
}

// "Filter" nav opens the filter panel (the logo is now a plain home link). The
// panel filters the home feed and — on archive day pages — that day's articles.
function toggleSettings() {
  const opening = settingsView && settingsView.hidden;
  showView(opening ? "settings" : "feed");
  if (opening) {
    loadData();          // ensure filter panels are populated (esp. on archive pages)
    loadArchiveDates();  // populate the Archive day list (Today + last 10 days)
  }
}
if (filterToggle) filterToggle.addEventListener("click", toggleSettings);
if (moreToggle) {
  moreToggle.addEventListener("click", () => {
    showView(moreView && moreView.hidden ? "more" : "feed");
  });
}

// ---------- Feed-settings group headers ----------
// On mobile the header expands/collapses the group (the list is hidden until
// open). On desktop the list is always visible, so the header is just a label —
// select-all / deselect-all is the explicit ".fs-all" button (#2).
const mobile = window.matchMedia("(max-width: 760px)");
for (const head of document.querySelectorAll(".fs-head")) {
  head.addEventListener("click", (e) => {
    if (mobile.matches) {
      e.preventDefault();
      head.closest(".fs-group").classList.toggle("open");
    }
  });
}

// "Select all" / "Deselect all" buttons under each group.
for (const btn of document.querySelectorAll(".fs-all")) {
  btn.addEventListener("click", () => {
    const g = btn.dataset.group;
    if (g === "country") toggleAllCountries();
    else if (g === "lang") toggleAllLangs();
    else if (g === "media") toggleAllMedia();
  });
}

// ---------- Welcome modal & primary country/language detection ----------
// True when the active country/language filter came from auto-detection or a
// remembered preference (not from an explicit user click). Such defaults get
// relaxed rather than ever showing an empty feed.
let autoDefault = false;
// Set at boot for a first-time home-page visit; the welcome modal is shown once
// crawled.json has loaded (so detected language can be validated against sources).
let firstVisit = false;

// A browser language often has no sources in the detected country (e.g. an
// English browser in Germany). Rather than show nothing, drop the language
// constraint first, then the country, until the auto-applied default is non-empty.
// Only runs for auto-applied defaults (autoDefault) — an explicit user selection is
// honoured exactly, empty or not (see afterFilterChange).
function relaxIfEmpty() {
  if (!current.length) return;
  const visible = () => current.filter((a) => !isExcluded(a) && matchesQuery(a)).length;
  if (visible() > 0) return;
  if (!langsAll) { langsAll = true; includedLangs.clear(); persistFilters(); }
  if (visible() > 0) return;
  if (!countriesAll) { countriesAll = true; includedCountries.clear(); persistFilters(); }
}

// Timezone → ISO country, a no-network fallback when /cdn-cgi/trace is blocked.
// Covers the countries we carry; extend alongside COUNTRY_NAMES.
const TZ_COUNTRY = {
  "Europe/Zurich": "CH", "Europe/Berlin": "DE", "Europe/Paris": "FR", "Europe/Rome": "IT",
  "Europe/Madrid": "ES", "Europe/London": "GB", "Europe/Amsterdam": "NL", "Europe/Brussels": "BE",
  "Europe/Vienna": "AT", "Europe/Lisbon": "PT", "Europe/Dublin": "IE", "Europe/Warsaw": "PL",
  "Europe/Stockholm": "SE", "Europe/Oslo": "NO", "Europe/Copenhagen": "DK", "Europe/Helsinki": "FI",
  "Europe/Athens": "GR", "Europe/Prague": "CZ", "Europe/Budapest": "HU", "Europe/Bucharest": "RO",
  "Europe/Kyiv": "UA", "Europe/Kiev": "UA", "Europe/Istanbul": "TR",
  "America/Toronto": "CA", "America/Vancouver": "CA", "America/Montreal": "CA",
  "America/Mexico_City": "MX", "America/Sao_Paulo": "BR", "America/Argentina/Buenos_Aires": "AR",
  "America/Bogota": "CO", "America/Lima": "PE",
  "America/New_York": "US", "America/Chicago": "US", "America/Denver": "US", "America/Los_Angeles": "US",
  "Australia/Sydney": "AU", "Australia/Melbourne": "AU", "Pacific/Auckland": "NZ",
  "Asia/Kolkata": "IN", "Asia/Tokyo": "JP", "Asia/Seoul": "KR", "Asia/Singapore": "SG",
  "Asia/Jakarta": "ID", "Asia/Manila": "PH", "Asia/Ho_Chi_Minh": "VN", "Asia/Karachi": "PK",
  "Asia/Jerusalem": "IL", "Asia/Qatar": "QA", "Asia/Hong_Kong": "HK",
  "Asia/Shanghai": "CN", "Asia/Chongqing": "CN", "Asia/Urumqi": "CN",
  "Europe/Moscow": "RU", "Europe/Samara": "RU", "Asia/Yekaterinburg": "RU",
  "Asia/Novosibirsk": "RU", "Asia/Krasnoyarsk": "RU", "Asia/Vladivostok": "RU",
};

// Best-effort visitor country (ISO alpha-2): Cloudflare edge IP first, then
// timezone, then the browser locale's region. null if undeterminable.
async function detectCountry() {
  try {
    const txt = await fetch("/cdn-cgi/trace", { cache: "no-store" }).then((r) => r.text());
    const m = txt.match(/^loc=([A-Z]{2})/m);
    if (m) return m[1];
  } catch (e) { /* fall through */ }
  try {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
    if (TZ_COUNTRY[tz]) return TZ_COUNTRY[tz];
  } catch (e) { /* fall through */ }
  const region = ((navigator.languages || [navigator.language || ""])[0] || "").split("-")[1];
  return region && /^[A-Za-z]{2}$/.test(region) ? region.toUpperCase() : null;
}

// Best-effort preferred language (ISO 639-1) from the browser, limited to the
// languages we actually carry. null if none match.
function detectLanguage() {
  for (const tag of navigator.languages || [navigator.language || ""]) {
    const code = (tag || "").split("-")[0].toLowerCase();
    if (code in LANG_NAMES) return code;
  }
  return null;
}

// Apply a single primary country / language via the include model ("" = all).
function setPrimaryCountry(code) {
  includedCountries.clear();
  countriesAll = !code;
  if (code) includedCountries.add(code.toLowerCase());
}
function setPrimaryLang(code) {
  includedLangs.clear();
  langsAll = !code;
  if (code) includedLangs.add(code.toLowerCase());
}

function refreshFeed() {
  buildCountryFilters(); updateAllToggles();
  ensureCountryData().then(() => {
    if (autoDefault) { relaxIfEmpty(); return ensureCountryData(); }
    return current;
  }).then(() => {
    buildFilters(current); buildLangFilters(current); updateAllToggles();
    if (current.length) render(current, sortMode());
    else applySsrFilter();
  });
}

function showWelcome(code, langCode) {
  const country = code && (code in COUNTRY_NAMES) ? code : null;
  const cName = country ? COUNTRY_NAMES[country] : "around the world";
  // The detected browser language may not exist for this country (e.g. an
  // English browser visiting from Switzerland). Only offer a language the
  // country actually publishes in, falling back to its predominant one.
  let lang = langCode && (langCode in LANG_NAMES) ? langCode : null;
  if (country) {
    const avail = langsForCountry(country);
    if (avail.length && (!lang || !avail.includes(lang))) lang = avail[0];
  }
  const lName = lang ? LANG_NAMES[lang] : null;
  const sentence = lName
    ? `Based on your location you see all.news from <span class="country">${esc(cName)}</span> in <span class="lang">${esc(lName)}</span>.`
    : `Based on your location you see all.news from <span class="country">${esc(cName)}</span>.`;
  const overlay = document.createElement("div");
  overlay.id = "welcomeOverlay";
  overlay.className = "welcome-overlay";
  overlay.innerHTML =
    '<div class="welcome-modal" role="dialog" aria-modal="true" aria-labelledby="welcomeTitle">' +
    '<h2 id="welcomeTitle">Welcome.</h2>' +
    `<p>${sentence}</p>` +
    '<div class="welcome-actions">' +
    '<button type="button" class="change">Change</button>' +
    '<button type="button" class="continue">Continue ✓</button>' +
    '</div></div>';
  document.body.appendChild(overlay);
  const close = () => { overlay.remove(); lsSet(STORE_WELCOMED, "1"); };
  const apply = () => {
    setPrimaryCountry(country);
    setPrimaryLang(lang);
    autoDefault = true; // relax the combo rather than show an empty feed
    persistFilters();
    close();
    refreshFeed();
  };
  // "Change" applies the detected setting, then opens the menu so the user sees
  // everything deselected except their auto-selected country/language.
  const change = () => { apply(); showView("settings"); };
  overlay.querySelector(".continue").addEventListener("click", apply);
  overlay.querySelector(".change").addEventListener("click", change);
  // The underlined country/language names are also shortcuts to change them.
  overlay.querySelectorAll(".country, .lang").forEach((el) => el.addEventListener("click", change));
}

// ---------- Boot ----------
const dayParam = new URLSearchParams(location.search).get("day");
if (dayParam) {
  // Redirect legacy ?day= URLs to static archive pages
  location.replace(`/archive/${dayParam}.html`);
} else {
  // archive/2026-06-07.html (or -2, -3 …) → 2026-06-07.json (sibling); else /crawled.json
  const archiveMatch = location.pathname.match(/\/archive\/(\d{4}-\d{2}-\d{2})(?:-\d+)?\.html$/);
  // Landing page: /news/<country>/<lang>/ → resolve the slugs back to codes.
  const landingMatch = location.pathname.match(/^\/news\/([a-z0-9-]+)\/([a-z0-9-]+)\/?$/);
  const landingCC = landingMatch ? COUNTRY_BY_SLUG[landingMatch[1]] : null;
  const landingLang = landingMatch ? LANG_BY_SLUG[landingMatch[2]] : null;
  isLanding = !!(landingCC && landingLang);
  DATA_URL = archiveMatch ? `${archiveMatch[1]}.json` : "/crawled.json";
  isArchive = !!archiveMatch; // archive days keep the single-file model; home shards by country
  // Filter state was already loaded from localStorage at module init; is anything
  // actually narrowing the feed?
  const hasFilter = excluded.size || !countriesAll || !langsAll || query;

  if (archiveMatch) {
    // Archive day page: static paginated HTML. The saved filter (loaded from
    // localStorage) applies here too; pre-filter the SSR rows, then re-render that
    // day from its JSON. (The Filter menu is present on every archive day page.)
    if (hasFilter) {
      autoDefault = true; // relax rather than show an empty day if a pick empties it
      applySsrFilter();
      loadData().then(() => { if (current.length) render(current, sortMode()); });
    }
  } else if (isLanding) {
    // Landing page: the path fixes the country + language. Behave like a filtered
    // home view (shards by country), no welcome modal / saved defaults. The SSR
    // slice is already the right articles, so there's no flash before hydration.
    setPrimaryCountry(landingCC);
    setPrimaryLang(landingLang);
    loadData().then(() => { if (current.length) render(current, sortMode()); });
  } else {
    // Home page. Filter state was restored from localStorage at init.
    if (lsGet(STORE_WELCOMED)) {
      // Returning visitor: their saved filter relaxes rather than ever emptying the
      // feed. Pre-filter the SSR head so there's no flash before crawled.json loads.
      if (hasFilter) { autoDefault = true; applySsrFilter(); }
    } else {
      firstVisit = true; // first visit: welcome modal after data loads
    }
    loadData().then(() => {
      if (current.length) render(current, sortMode()); // home always takes over (windowed)
      if (firstVisit) {
        firstVisit = false;
        detectCountry().then((c) => showWelcome(c, detectLanguage()));
      }
    });
  }
}

const searchInput = document.getElementById("search");
const searchClear = document.getElementById("searchClear");
// Toggle the magnifier ⇄ × icon based on whether there's a query.
function syncSearchIcon() {
  const wrap = searchInput && searchInput.closest(".search-wrap");
  if (wrap) wrap.classList.toggle("has-query", !!searchInput.value);
}
// Search doesn't change the country/language selection, so it only needs the data
// for the active selection (already loaded on home; fetched here on archive pages'
// first search) — no panel rebuild. Searches within the loaded feed, as before.
function searchRerender() {
  ensureCountryData().then(() => {
    if (current.length) render(current, sortMode());
    else applySsrFilter();
  });
}
if (searchInput) {
  searchInput.value = query;
  syncSearchIcon();
  searchInput.addEventListener("input", () => {
    query = searchInput.value.trim().toLowerCase();
    syncSearchIcon();
    persistFilters();
    searchRerender();
  });
}
if (searchClear) {
  searchClear.addEventListener("click", () => {
    if (!searchInput) return;
    searchInput.value = "";
    query = "";
    syncSearchIcon();
    persistFilters();
    searchInput.focus();
    searchRerender();
  });
}

// ---------- Article sharing & deep-link highlighting ----------
// "Share" copies a link to the article's anchor on this page; arriving
// with that #hash highlights the row and scrolls it to the top.
function highlightFromHash() {
  const id = decodeURIComponent(location.hash.slice(1));
  for (const el of document.querySelectorAll(".article.highlight")) {
    el.classList.remove("highlight");
  }
  if (!id) return;
  const el = document.getElementById(id);
  if (el) {
    el.classList.add("highlight");
    el.scrollIntoView({ block: "start", behavior: "auto" });
  }
}

function shareArticle(li, btn) {
  const url = `${location.origin}${location.pathname}#${li.id}`;
  const done = () => {
    const label = btn.querySelector(".label");
    if (!label || btn.dataset.copied) return; // guard against rapid re-clicks
    const prev = label.textContent;
    btn.dataset.copied = "1";
    label.textContent = "Link copied ✓";
    setTimeout(() => { label.textContent = prev; delete btn.dataset.copied; }, 1500);
  };
  // On touch devices hand off to the OS share sheet, which beats copying a link
  // the visitor then has to paste somewhere (#49). Gated on a coarse pointer
  // because desktop browsers also expose navigator.share, where the clipboard is
  // the better behaviour. A cancelled sheet (AbortError) is not a failure, so it
  // must not fall through to the clipboard or flash "Link copied".
  const titleEl = li.querySelector(".title");
  if (navigator.share && matchMedia("(pointer: coarse)").matches) {
    navigator.share({ title: titleEl ? titleEl.textContent : document.title, url })
      .catch((e) => { if (e && e.name !== "AbortError") copyToClipboard(url, done); });
    return;
  }
  copyToClipboard(url, done);
}

// Copy `url`, calling `done` either way. Falls back to a hidden textarea +
// execCommand on browsers without the async clipboard API.
function copyToClipboard(url, done) {
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(url).then(done, done);
  } else {
    const ta = document.createElement("textarea");
    ta.value = url;
    ta.style.position = "fixed";
    ta.style.opacity = "0";
    document.body.appendChild(ta);
    ta.select();
    try { document.execCommand("copy"); } catch (e) { /* ignore */ }
    ta.remove();
    done();
  }
}

// Hide / unhide a source (reuses the Medias exclude model), then refresh panels.
function setSourceHidden(name, hidden) {
  const lc = name.toLowerCase();
  if (hidden) excluded.add(lc); else excluded.delete(lc);
  persistFilters();
  if (current.length) { buildFilters(current); render(current, sortMode()); }
  else applySsrFilter();
}

// Confirmation popup before hiding a source (#4): explains the action and points
// to where it can be undone, so an accidental click never silently hides a source.
function confirmHide(name) {
  const overlay = document.createElement("div");
  overlay.className = "confirm-overlay";
  overlay.innerHTML =
    '<div class="confirm-modal" role="dialog" aria-modal="true" aria-labelledby="confirmTitle">' +
    '<h2 id="confirmTitle">Hide this provider?</h2>' +
    '<p>You can always show it again in your feed ' +
    '<button type="button" class="settings-link">settings <svg width="12" height="12"><use href="#ico-arrow"/></svg></button></p>' +
    '<div class="confirm-actions">' +
    '<button type="button" class="cancel">No, cancel ✕</button>' +
    '<button type="button" class="confirm">Yes, hide ✓</button>' +
    '</div></div>';
  document.body.appendChild(overlay);
  const close = () => { overlay.remove(); document.removeEventListener("keydown", onKey); };
  const onKey = (ev) => { if (ev.key === "Escape") close(); };
  document.addEventListener("keydown", onKey);
  overlay.addEventListener("click", (ev) => { if (ev.target === overlay) close(); });
  overlay.querySelector(".cancel").addEventListener("click", close);
  overlay.querySelector(".confirm").addEventListener("click", () => { setSourceHidden(name, true); close(); });
  overlay.querySelector(".settings-link").addEventListener("click", () => {
    close();
    showView("settings");
    loadData();
    loadArchiveDates();
  });
}

// Touch devices have no hover, so a row stays a plain headline until tapped (#30).
// The first tap "opens" the row (white card + Open/Share); a second tap on a link
// then navigates. Only one row is open at a time.
const TOUCH = window.matchMedia("(hover: none)").matches;
function setActiveArticle(li) {
  for (const el of document.querySelectorAll(".article.active")) {
    if (el !== li) el.classList.remove("active");
  }
  if (li) li.classList.add("active");
}

document.addEventListener("click", (e) => {
  // Eye-off next to the time asks to hide that source from the feed (#4). A
  // confirmation popup explains the action first, so an accidental click can't
  // silently make a source disappear. Works on every device.
  const hideBtn = e.target.closest(".hide-src");
  if (hideBtn) {
    const li = hideBtn.closest(".article");
    const srcEl = li && li.querySelector(".source");
    const name = srcEl ? srcEl.textContent.trim() : "";
    if (name) confirmHide(name);
    hideBtn.blur();
    return;
  }

  // Touch: tap-to-open (#30). The first tap on a row selects it — white card,
  // eye, Open/Share — and it becomes the only selected row (any other is
  // de-selected). That tap never navigates. Tapping the same row again does
  // nothing; only the explicit Open / Share / source pill act.
  if (TOUCH) {
    const li = e.target.closest(".article");
    if (!li) return;                        // taps outside a row keep the selection
    if (!li.classList.contains("active")) {
      e.preventDefault();                   // first tap only selects, never navigates
      setActiveArticle(li);                 // and de-selects whatever was open
      return;
    }
    const share = e.target.closest(".row-act.share");
    if (share) { shareArticle(li, share); share.blur(); return; }
    if (e.target.closest(".row-act.open") || e.target.closest(".source")) return; // navigate
    e.preventDefault();                     // re-tapping the open row: no change
    return;
  }

  // ---- Desktop (hover) ----
  const btn = e.target.closest(".row-act.share");
  if (btn) {
    const li = btn.closest(".article");
    if (li) shareArticle(li, btn);
    // Don't keep focus on the button: :focus-within would otherwise hold the
    // row's white "card" state open after the pointer leaves.
    btn.blur();
    return;
  }
  // Title link, "Open" and the source pill navigate on their own; just drop
  // focus so :focus-within doesn't leave the card stuck in its white state.
  const link = e.target.closest(".article a");
  if (link) {
    link.blur();
    return;
  }
  // Clicking anywhere else on the card opens the article in a new tab —
  // unless the user is selecting text.
  const sel = window.getSelection();
  if (sel && sel.toString()) return;
  const li = e.target.closest(".article");
  if (li) {
    const title = li.querySelector("a.title");
    if (title) window.open(title.href, "_blank", "noopener");
  }
});

window.addEventListener("hashchange", highlightFromHash);
highlightFromHash(); // honor an initial #hash on the server-rendered list
